  describe "error_handling_invalid_syntax" do
    test "error_handling_invalid_syntax" do
      {:ok, result} = TreeSitterLanguagePack.process("function function function @@@ %%%", "{\"language\":\"javascript\"}")
    end
  end

  describe "error_handling_unknown_language" do
    test "error_handling_unknown_language" do
      assert {:error, _} = TreeSitterLanguagePack.process("", "{\"language\":\"nonexistent_xyz\"}")
    end
  end

  describe "error_process_empty_source" do
    test "error_process_empty_source" do
      {:ok, result} = TreeSitterLanguagePack.process("", "{\"language\":\"python\"}")
      assert result.metrics.total_lines == 0
    end
  end

  describe "parse_empty_language" do
    test "parse_empty_language" do
      assert {:error, _} = TreeSitterLanguagePack.process("x = 1", "{\"language\":\"\"}")
    end
  end

  describe "process_unknown_language" do
    test "process_unknown_language" do
      assert {:error, _} = TreeSitterLanguagePack.process("x = 1", "{\"language\":\"nonexistent_xyz\"}")
